import React, { useState, useEffect, useRef } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { User, ShoppingCart, ChevronDown } from 'lucide-react';
import './Header.css';

const Header = ({ cartCount }) => {
  const [isProfileDropdownOpen, setIsProfileDropdownOpen] = useState(false);
  const [userName, setUserName] = useState('Account');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const dropdownRef = useRef(null);
  const navigate = useNavigate();

  useEffect(() => {
    // Check login status on mount
    checkLoginStatus();

    // Add click outside listener to close the dropdown
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        setIsProfileDropdownOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const checkLoginStatus = () => {
    // In a real app, this would check auth state
    // For now we'll use localStorage as a demo
    const userData = localStorage.getItem('userData');
    if (userData) {
      const user = JSON.parse(userData);
      setUserName(user.name || 'Account');
      setIsLoggedIn(true);
    } else {
      setUserName('Account');
      setIsLoggedIn(false);
    }
  };

  const toggleProfileDropdown = () => {
    setIsProfileDropdownOpen(!isProfileDropdownOpen);
  };

  const handleLogout = () => {
    // Clear user data
    localStorage.removeItem('userData');
    setIsProfileDropdownOpen(false);
    setIsLoggedIn(false);
    setUserName('Account');

    // In a real app, you would also handle token/session invalidation here

    // Navigate to home
    navigate('/');

    // If vanilla JS app exists, call its logout method
    if (window.app && typeof window.app.logout === 'function') {
      window.app.logout();
    }
  };

  return (
    <header className="header">
      <Link to="/" className="logo">
        <span className="logo-text">Mankind Matrix</span>
      </Link>

      <div className="search-container">
        <input 
          type="text" 
          className="search-input" 
          placeholder="Search..." 
        />
        <button className="search-button">Search</button>
      </div>

      <nav className="nav-links">
        <div className="profile-dropdown-container" ref={dropdownRef}>
          <button 
            className="profile-button" 
            onClick={toggleProfileDropdown}
            aria-expanded={isProfileDropdownOpen}
            aria-haspopup="true"
          >
            <User size={20} />
            <span>{userName}</span>
            <ChevronDown size={16} />
          </button>

          {isProfileDropdownOpen && (
            <div className="profile-dropdown">
              {isLoggedIn ? (
                <>
                  <Link to="/account" onClick={() => setIsProfileDropdownOpen(false)}>Account Dashboard</Link>
                  <Link to="/profile" onClick={() => setIsProfileDropdownOpen(false)}>Profile Settings</Link>
                  <Link to="/orders" onClick={() => setIsProfileDropdownOpen(false)}>Your Orders</Link>
                  <Link to="/addresses" onClick={() => setIsProfileDropdownOpen(false)}>Your Addresses</Link>
                  <button className="logout-button" onClick={handleLogout}>Logout</button>
                </>
              ) : (
                <>
                  <Link to="/login" onClick={() => setIsProfileDropdownOpen(false)}>Login</Link>
                  <Link to="/register" onClick={() => setIsProfileDropdownOpen(false)}>Register</Link>
                </>
              )}
            </div>
          )}
        </div>

        <Link to="/cart" className="cart-button">
          <ShoppingCart size={20} />
          <span>Cart</span>
          {cartCount > 0 && <span className="cart-count">{cartCount}</span>}
        </Link>
      </nav>
    </header>
  );
};

export default Header;
